<?php
 namespace WPAICG\AutoGPT\Cron\Scheduler\Batch; use WPAICG\AutoGPT\Cron\Scheduler\Schedule; if (!defined('ABSPATH')) { exit; } function clear_all_task_events_logic(): void { global $wpdb; $tasks_table_name = $wpdb->prefix . 'aipkit_automated_tasks'; if ($wpdb->get_var("SHOW TABLES LIKE '" . esc_sql($tasks_table_name) . "'") != $tasks_table_name) { return; } $task_ids = $wpdb->get_col("SELECT id FROM " . esc_sql($tasks_table_name)); if ($task_ids) { foreach ($task_ids as $task_id) { Schedule\clear_task_event_logic(absint($task_id)); } } } 